class DeepLinkHandler {
    companion object {
        private const val SCHEME = "myapp"
        private const val PROFILE_PATH = "profile"
        private const val PAYMENT_PATH = "payment"
        
        fun handleDeepLink(uri: Uri, context: Context): Boolean {
            if (uri.scheme != SCHEME) return false
            
            val path = uri.pathSegments
            when (path.firstOrNull()) {
                PROFILE_PATH -> {
                    val userId = path.getOrNull(1)
                    if (userId != null) {
                        val intent = Intent(context, ProfileActivity::class.java)
                        intent.putExtra("user_id", userId)
                        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                        context.startActivity(intent)
                        return true
                    }
                }
                PAYMENT_PATH -> {
                    val action = path.getOrNull(1)
                    if (action == "confirm") {
                        val intent = Intent(context, PaymentConfirmationActivity::class.java)
                        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK
                        context.startActivity(intent)
                        return true
                    }
                }
            }
            return false
        }
    }
}

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        handleDeepLinkIntent()
    }
    
    private fun handleDeepLinkIntent() {
        val intent = intent
        val action = intent.action
        val uri = intent.data
        
        if (Intent.ACTION_VIEW == action && uri != null) {
            DeepLinkHandler.handleDeepLink(uri, this)
        }
    }
